TIERA_STYLES = '\n@import url(\'https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600&family=JetBrains+Mono:wght@500;600&display=swap\');\n\n/* ── Reset & root ── */\n:root {\n  --bg:        #FFFFFF;\n  --sidebar:   #FAFAFA;\n  --border:    #EDEDED;\n  --text:      #111111;\n  --muted:     #888888;\n  --accent:    #000000;\n  --danger:    #CC0000;\n  --radius:    6px;\n}\n\nhtml, body,\n[data-testid="stApp"],\n[data-testid="stAppViewContainer"] {\n  background: var(--bg) !important;\n  color: var(--text) !important;\n  font-family: \'Inter\', sans-serif;\n  font-size: 13px;\n}\n\n/* hide Streamlit chrome */\nheader[data-testid="stHeader"],\n#MainMenu, footer,\n[data-testid="stToolbar"] { display: none !important; }\n\n/* zero-pad the page */\n.main .block-container {\n  max-width: 100% !important;\n  padding: 0 !important;\n  height: 100vh !important;\n  overflow: hidden !important;\n}\n\n/* ── Top-level 2-col layout ── */\n.main [data-testid="stHorizontalBlock"]:first-of-type {\n  gap: 0 !important;\n  align-items: stretch !important;\n  height: 100vh !important;\n}\n.main [data-testid="stHorizontalBlock"]:first-of-type\n  > [data-testid="stColumn"]:first-child {\n  flex: 0 0 280px !important;\n  max-width: 280px !important;\n  min-width: 280px !important;\n  height: 100vh !important;\n  overflow: hidden !important;\n  border-right: 1px solid var(--border) !important;\n  background: var(--sidebar) !important;\n  padding: 0 !important;\n}\n.main [data-testid="stHorizontalBlock"]:first-of-type\n  > [data-testid="stColumn"]:last-child {\n  flex: 1 1 auto !important;\n  height: 100vh !important;\n  overflow: hidden !important;\n  padding: 0 !important;\n}\n\n/* prevent nested columns in sidebar from inheriting the 280px rule */\n[data-testid="stColumn"] [data-testid="stColumn"] {\n  flex: unset !important;\n  max-width: unset !important;\n  min-width: unset !important;\n}\n\n/* ── Map iframe fills right column ── */\n.main [data-testid="stHorizontalBlock"]:first-of-type\n  > [data-testid="stColumn"]:last-child\n  .stCustomComponentV1,\n.main [data-testid="stHorizontalBlock"]:first-of-type\n  > [data-testid="stColumn"]:last-child\n  .stCustomComponentV1 iframe {\n  width: 100% !important;\n  height: 100vh !important;\n  display: block !important;\n}\n\n/* ── Sidebar inner padding ── */\n[data-testid="stColumn"]:first-child .block-container,\n[data-testid="stColumn"]:first-child > div {\n  padding: 0 !important;\n  height: 100% !important;\n}\n[data-testid="stColumn"]:first-child\n  [data-testid="stVerticalBlockBorderWrapper"],\n[data-testid="stColumn"]:first-child\n  [data-testid="stVerticalBlock"] {\n  padding: 0 !important;\n  gap: 0 !important;\n}\n\n/* ── Brand block ── */\n.t-brand {\n  padding: 1.35rem 1.1rem 1rem;\n  border-bottom: 1px solid var(--border);\n}\n.t-brand-name {\n  font-family: \'JetBrains Mono\', monospace;\n  font-size: 13px;\n  font-weight: 600;\n  letter-spacing: 0.22em;\n  color: var(--text);\n}\n.t-brand-sub {\n  font-size: 10px;\n  color: var(--muted);\n  margin-top: 2px;\n  letter-spacing: 0.04em;\n}\n\n/* ── Stepper ── */\n.t-stepper {\n  padding: 0.9rem 1.1rem 0.7rem;\n  display: flex;\n  flex-direction: column;\n  gap: 4px;\n}\n.t-step {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  padding: 3px 0;\n}\n.t-step-dot {\n  width: 7px; height: 7px;\n  border-radius: 50%;\n  flex-shrink: 0;\n  background: var(--border);\n}\n.t-step--active .t-step-dot { background: var(--accent); }\n.t-step--done   .t-step-dot { background: var(--muted); }\n.t-step-label {\n  font-size: 11px;\n  color: var(--muted);\n  letter-spacing: 0.04em;\n}\n.t-step--active .t-step-label { color: var(--text); font-weight: 600; }\n.t-step--done   .t-step-label { color: var(--muted); }\n\n/* ── Divider ── */\n.t-divider {\n  height: 1px;\n  background: var(--border);\n  margin: 0 0 0.6rem;\n}\n\n/* ── Section & typography ── */\n.t-section {\n  font-size: 11px;\n  font-weight: 600;\n  letter-spacing: 0.12em;\n  text-transform: uppercase;\n  color: var(--text);\n  padding: 0 1.1rem 0.65rem;\n}\n.t-field-label {\n  font-size: 10px;\n  font-weight: 600;\n  letter-spacing: 0.14em;\n  text-transform: uppercase;\n  color: var(--muted);\n  padding: 0 1.1rem 0.25rem;\n}\n.t-hint {\n  font-size: 11px;\n  color: var(--muted);\n  padding: 0.25rem 1.1rem;\n  line-height: 1.5;\n}\n.t-gap { height: 0.6rem; }\n.t-coord {\n  font-size: 11px;\n  color: #338833;\n  padding: 0.15rem 1.1rem;\n  font-family: \'JetBrains Mono\', monospace;\n}\n.t-status {\n  font-size: 11px;\n  color: var(--muted);\n  padding: 0.25rem 1.1rem 0.4rem;\n  line-height: 1.5;\n}\n.t-via {\n  font-size: 11px;\n  font-family: \'JetBrains Mono\', monospace;\n  color: var(--text);\n  padding: 0.2rem 1.1rem;\n}\n.t-warn {\n  font-size: 11px;\n  color: var(--danger);\n  padding: 0.25rem 1.1rem;\n}\n.t-success {\n  padding: 1.5rem 1.1rem;\n  font-size: 13px;\n  line-height: 1.7;\n  color: var(--text);\n  border: 1px solid var(--border);\n  border-radius: var(--radius);\n  margin: 0.8rem 1.1rem;\n  background: #F8F8F8;\n}\n\n/* ── Instruction nodes ── */\n.t-node {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  padding: 0.45rem 1.1rem;\n  cursor: pointer;\n  border-left: 2px solid transparent;\n}\n.t-node--active {\n  border-left-color: var(--text);\n  background: #F5F5F5;\n}\n.t-node-num {\n  width: 20px; height: 20px;\n  border-radius: 50%;\n  border: 1.5px solid var(--text);\n  display: flex; align-items: center; justify-content: center;\n  font-size: 10px; font-weight: 600;\n  flex-shrink: 0;\n  font-family: \'JetBrains Mono\', monospace;\n}\n.t-node--active .t-node-num {\n  background: var(--text);\n  color: var(--bg);\n}\n.t-node-meta {\n  font-size: 10px;\n  letter-spacing: 0.1em;\n  color: var(--muted);\n  text-transform: uppercase;\n}\n.t-node-text {\n  font-size: 11px;\n  color: var(--muted);\n  padding: 0.2rem 1.1rem 0.4rem 2.7rem;\n  line-height: 1.5;\n}\n\n/* ── Streamlit widget overrides ── */\n[data-testid="stTextInput"] input,\n[data-testid="stTextArea"] textarea,\n[data-testid="stNumberInput"] input,\n[data-baseweb="select"] > div {\n  background: var(--bg) !important;\n  border: 1px solid var(--border) !important;\n  border-radius: var(--radius) !important;\n  color: var(--text) !important;\n  font-family: \'Inter\', sans-serif !important;\n  font-size: 12px !important;\n}\n[data-testid="stTextInput"] input:focus,\n[data-testid="stTextArea"] textarea:focus {\n  border-color: var(--text) !important;\n  box-shadow: none !important;\n  outline: none !important;\n}\nlabel, [data-testid="stWidgetLabel"] {\n  font-size: 11px !important;\n  color: var(--muted) !important;\n}\n\n/* ── Buttons ── */\n.stButton > button {\n  background: var(--bg) !important;\n  color: var(--text) !important;\n  border: 1px solid var(--border) !important;\n  border-radius: var(--radius) !important;\n  font-size: 12px !important;\n  font-weight: 500 !important;\n  padding: 0.35rem 0.6rem !important;\n  box-shadow: none !important;\n  transition: border-color 0.15s, background 0.15s !important;\n}\n.stButton > button:hover {\n  border-color: #999 !important;\n}\n.stButton > button[kind="primary"] {\n  background: var(--text) !important;\n  color: var(--bg) !important;\n  border-color: var(--text) !important;\n}\n.stButton > button[kind="primary"]:hover {\n  background: #333 !important;\n}\n.stButton > button:disabled {\n  opacity: 0.35 !important;\n  cursor: not-allowed !important;\n}\n.stDownloadButton > button {\n  background: var(--bg) !important;\n  color: var(--text) !important;\n  border: 1px solid var(--border) !important;\n  border-radius: var(--radius) !important;\n  font-size: 12px !important;\n}\n\n/* selectbox */\n[data-baseweb="select"] [data-baseweb="select-option"] {\n  font-size: 12px !important;\n}\n/* expander */\ndiv[data-testid="stExpander"] {\n  border: 1px solid var(--border) !important;\n  border-radius: var(--radius) !important;\n}\n/* alert */\ndiv[data-testid="stAlert"] { border-radius: var(--radius) !important; }\n\n/* ── Sidebar padding fixups ── */\n.main [data-testid="stHorizontalBlock"]:first-of-type\n  > [data-testid="stColumn"]:first-child\n  [data-testid="stWidgetLabel"] {\n  padding-left: 1.1rem;\n}\n.main [data-testid="stHorizontalBlock"]:first-of-type\n  > [data-testid="stColumn"]:first-child\n  [data-testid="stTextInput"],\n.main [data-testid="stHorizontalBlock"]:first-of-type\n  > [data-testid="stColumn"]:first-child\n  [data-testid="stTextArea"],\n.main [data-testid="stHorizontalBlock"]:first-of-type\n  > [data-testid="stColumn"]:first-child\n  [data-testid="stButton"] {\n  padding-left: 1.1rem !important;\n  padding-right: 1.1rem !important;\n}\n\n/* ── Scrollable node container fix ── */\n[data-testid="stVerticalBlock"][data-height] {\n  overflow-y: auto !important;\n}\n\n/* ── Hide bridge input ── */\n.element-container:has(input[aria-label="tiera-bridge"]) { display: none; }\n'
